{
  "name": "DevCanvas AI Refiner",
  "description": "A professional developer workbench for importing, managing, and iterating on existing code snippets using the Gemini 3 Pro model. Perfect for resuming work from previous sessions and refining UI/UX."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface CodeFile {
  id: string;
  name: string;
  content: string;
  language: string;
}

export interface Project {
  id: string;
  name: string;
  files: CodeFile[];
  updatedAt: number;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'assistant';
  text: string;
  timestamp: number;
}

export enum ViewMode {
  EDITOR = 'editor',
  PREVIEW = 'preview',
  CHAT = 'chat'
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { CodeFile, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const refineCode = async (
  files: CodeFile[],
  instruction: string,
  history: ChatMessage[]
): Promise<string> => {
  const model = "gemini-3-pro-preview";

  const filesContext = files.map(f => `File: ${f.name}\n\`\`\`${f.language}\n${f.content}\n\`\`\``).join('\n\n');

  const systemInstruction = `
    You are a world-class senior frontend engineer. 
    Context:
    ${filesContext}

    Task:
    Analyze the existing code above and apply the requested changes or improvements.
    Return a response that includes the updated code blocks and a brief explanation of what was changed.
    Use high-quality React and Tailwind patterns.
  `;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model,
    contents: instruction,
    config: {
      systemInstruction,
      temperature: 0.7,
      thinkingConfig: { thinkingBudget: 4000 }
    },
  });

  return response.text || "No response from AI.";
};

export const suggestImprovements = async (files: CodeFile[]): Promise<string> => {
  const model = "gemini-3-flash-preview";
  const filesContext = files.map(f => `File: ${f.name}\n${f.content}`).join('\n\n');

  const response = await ai.models.generateContent({
    model,
    contents: `Analyze these files and suggest 3 high-impact UI/UX improvements or feature additions:\n\n${filesContext}`,
  });

  return response.text || "I couldn't generate suggestions at this time.";
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  CodeFile, 
  Project, 
  ChatMessage, 
  ViewMode 
} from './types';
import { refineCode, suggestImprovements } from './services/geminiService';

// Standard icons as functional components
const IconPlus = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>;
const IconCode = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="16 18 22 12 16 6"/><polyline points="8 6 2 12 8 18"/></svg>;
const IconMessage = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>;
const IconSend = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="22" y1="2" x2="11" y2="13"/><polyline points="22 2 15 22 11 13 2 9 22 2"/></svg>;
const IconChevronRight = () => <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="9 18 15 12 9 6"/></svg>;

const Sidebar: React.FC<{ 
  projects: Project[], 
  activeProjectId: string | null, 
  onSelectProject: (id: string) => void,
  onNewProject: () => void 
}> = ({ projects, activeProjectId, onSelectProject, onNewProject }) => (
  <aside className="w-72 bg-slate-950 border-r border-slate-800 flex flex-col h-full">
    <div className="p-6">
      <h1 className="text-xl font-bold text-white flex items-center gap-2">
        <span className="bg-blue-600 p-1.5 rounded-lg">AI</span> DevCanvas
      </h1>
    </div>

    <div className="px-4 mb-4">
      <button 
        onClick={onNewProject}
        className="w-full bg-blue-600 hover:bg-blue-500 text-white rounded-lg py-2.5 px-4 flex items-center justify-center gap-2 transition-all shadow-lg shadow-blue-900/20"
      >
        <IconPlus /> New Project
      </button>
    </div>

    <nav className="flex-1 overflow-y-auto px-2 space-y-1">
      <div className="px-3 py-2 text-xs font-semibold text-slate-500 uppercase tracking-wider">
        Recent Projects
      </div>
      {projects.map((p) => (
        <button
          key={p.id}
          onClick={() => onSelectProject(p.id)}
          className={`w-full text-left px-4 py-3 rounded-lg flex items-center gap-3 transition-colors ${
            activeProjectId === p.id 
              ? 'bg-slate-800 text-blue-400 border border-slate-700' 
              : 'text-slate-400 hover:bg-slate-900 hover:text-white'
          }`}
        >
          <div className="w-2 h-2 rounded-full bg-blue-500"></div>
          <span className="truncate flex-1">{p.name}</span>
          <IconChevronRight />
        </button>
      ))}
      {projects.length === 0 && (
        <div className="px-4 py-8 text-center text-slate-600 italic text-sm">
          No projects yet. Create one to start refining.
        </div>
      )}
    </nav>
  </aside>
);

const EditorArea: React.FC<{ 
  file: CodeFile, 
  onUpdate: (content: string) => void 
}> = ({ file, onUpdate }) => (
  <div className="flex-1 flex flex-col bg-slate-900 h-full">
    <div className="flex items-center gap-2 px-4 py-2 border-b border-slate-800 bg-slate-950">
      <IconCode />
      <span className="text-sm font-medium text-slate-300">{file.name}</span>
    </div>
    <textarea
      value={file.content}
      onChange={(e) => onUpdate(e.target.value)}
      className="flex-1 bg-slate-900 text-slate-200 code-font p-6 outline-none resize-none leading-relaxed text-sm selection:bg-blue-500/30"
      placeholder="Paste your existing React/HTML code here..."
    />
  </div>
);

const ChatPanel: React.FC<{
  messages: ChatMessage[],
  onSendMessage: (text: string) => void,
  isLoading: boolean
}> = ({ messages, onSendMessage, isLoading }) => {
  const [input, setInput] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim() && !isLoading) {
      onSendMessage(input);
      setInput('');
    }
  };

  return (
    <div className="w-[450px] bg-slate-950 border-l border-slate-800 flex flex-col h-full">
      <div className="p-4 border-b border-slate-800 flex items-center gap-2">
        <IconMessage />
        <h2 className="font-semibold text-white">Gemini AI Refiner</h2>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-6">
        {messages.length === 0 && (
          <div className="text-center py-10 px-4">
            <div className="w-16 h-16 bg-blue-900/20 rounded-full flex items-center justify-center mx-auto mb-4 border border-blue-800/30">
              <IconMessage />
            </div>
            <h3 className="text-white font-medium mb-2">Import & Improve</h3>
            <p className="text-slate-400 text-sm leading-relaxed">
              Paste your previous page code into the editor, then tell me what you want to add or change. I'll provide updated code blocks for you.
            </p>
          </div>
        )}
        {messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[90%] rounded-2xl px-4 py-3 text-sm ${
              m.role === 'user' 
                ? 'bg-blue-600 text-white' 
                : 'bg-slate-800 text-slate-200 border border-slate-700'
            }`}>
              <div className="whitespace-pre-wrap leading-relaxed">{m.text}</div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-slate-800 border border-slate-700 rounded-2xl px-4 py-3">
              <div className="flex gap-1.5">
                <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="p-4 border-t border-slate-800">
        <div className="relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="e.g., Add a dark mode toggle..."
            className="w-full bg-slate-900 border border-slate-800 rounded-xl py-3 pl-4 pr-12 text-sm text-slate-200 focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-all"
          />
          <button
            type="submit"
            disabled={isLoading || !input.trim()}
            className="absolute right-2 top-2 p-1.5 bg-blue-600 hover:bg-blue-500 disabled:bg-slate-700 text-white rounded-lg transition-all"
          >
            <IconSend />
          </button>
        </div>
      </form>
    </div>
  );
};

export default function App() {
  const [projects, setProjects] = useState<Project[]>([]);
  const [activeProjectId, setActiveProjectId] = useState<string | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [activeFileId, setActiveFileId] = useState<string | null>(null);

  // Initialize with an example project if empty
  useEffect(() => {
    const saved = localStorage.getItem('devcanvas_projects');
    if (saved) {
      const parsed = JSON.parse(saved);
      setProjects(parsed);
      if (parsed.length > 0) setActiveProjectId(parsed[0].id);
    } else {
      const defaultProject: Project = {
        id: 'p1',
        name: 'My Awesome Page',
        updatedAt: Date.now(),
        files: [{ id: 'f1', name: 'App.tsx', language: 'tsx', content: '// Paste your previous code here to start refining it!' }]
      };
      setProjects([defaultProject]);
      setActiveProjectId('p1');
      setActiveFileId('f1');
    }
  }, []);

  useEffect(() => {
    if (projects.length > 0) {
      localStorage.setItem('devcanvas_projects', JSON.stringify(projects));
    }
  }, [projects]);

  const activeProject = projects.find(p => p.id === activeProjectId) || null;
  const activeFile = activeProject?.files.find(f => f.id === (activeFileId || activeProject.files[0].id)) || null;

  const handleNewProject = () => {
    const newId = `p${Date.now()}`;
    const newProject: Project = {
      id: newId,
      name: 'Untitled Project',
      updatedAt: Date.now(),
      files: [{ id: `f${Date.now()}`, name: 'App.tsx', language: 'tsx', content: '' }]
    };
    setProjects([newProject, ...projects]);
    setActiveProjectId(newId);
    setMessages([]);
  };

  const handleUpdateFileContent = (content: string) => {
    if (!activeProjectId || !activeFile) return;
    setProjects(prev => prev.map(p => {
      if (p.id === activeProjectId) {
        return {
          ...p,
          files: p.files.map(f => f.id === activeFile.id ? { ...f, content } : f),
          updatedAt: Date.now()
        };
      }
      return p;
    }));
  };

  const handleSendMessage = async (text: string) => {
    if (!activeProject || !activeFile) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text,
      timestamp: Date.now()
    };
    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      const aiResponse = await refineCode(activeProject.files, text, messages);
      const assistantMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        text: aiResponse,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, assistantMsg]);
    } catch (error) {
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        text: "Sorry, I encountered an error processing your request. Please check your API configuration.",
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex h-screen w-screen overflow-hidden text-slate-200">
      <Sidebar 
        projects={projects} 
        activeProjectId={activeProjectId}
        onSelectProject={setActiveProjectId}
        onNewProject={handleNewProject}
      />

      <main className="flex-1 flex flex-col h-full">
        <header className="h-16 border-b border-slate-800 flex items-center justify-between px-6 bg-slate-950">
          <div className="flex items-center gap-4">
            <span className="text-sm text-slate-500">Project /</span>
            <input 
              value={activeProject?.name || ''} 
              onChange={(e) => {
                const val = e.target.value;
                setProjects(prev => prev.map(p => p.id === activeProjectId ? { ...p, name: val } : p));
              }}
              className="bg-transparent text-white font-medium outline-none focus:ring-1 focus:ring-blue-500/50 rounded px-2"
            />
          </div>
          <div className="flex items-center gap-3">
            <button className="px-3 py-1.5 text-xs bg-slate-800 hover:bg-slate-700 rounded-md transition-colors border border-slate-700">
              Reset
            </button>
            <button className="px-3 py-1.5 text-xs bg-blue-600 hover:bg-blue-500 rounded-md transition-colors font-medium">
              Export
            </button>
          </div>
        </header>

        <div className="flex-1 flex overflow-hidden">
          {activeFile ? (
            <EditorArea file={activeFile} onUpdate={handleUpdateFileContent} />
          ) : (
            <div className="flex-1 flex items-center justify-center bg-slate-900 text-slate-500">
              Select or create a file to begin
            </div>
          )}
          <ChatPanel 
            messages={messages} 
            onSendMessage={handleSendMessage} 
            isLoading={isLoading} 
          />
        </div>
      </main>
    </div>
  );
}
